1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	const CURSE_SURCHARGE_RATE = 0.5;
4	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
5	const HIGH_ENCHANTMENT_THRESHOLD = 5;
6	const CLAIM_ENCHANTMENT_THRESHOLD = 8;
7	const CLAIM_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
8	const LOYALTY_DISCOUNT_RATE = 0.2;
9	const LOYALTY_YEARS_THRESHOLD = 2;
10	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
11	
12	const BASE_PREMIUMS: Record<string, number> = {
13	  sword: 100,
14	  amulet: 60,
15	  staff: 80,
16	  potion: 40,
17	  rune: 25,
18	  moonstone: 25,
19	};
20	
21	const INSURANCE_VALUE_MULTIPLIER = 10;
22	
23	const DEDUCTIBLE = 100;
24	
25	const COMPONENT_BLOCK_PREMIUM: Record<string, number> = {
26	  rune: 60,
27	  moonstone: 60,
28	};
29	
30	function calculateBasePremium(items: any[]): number {
31	  const countsByType: Record<string, number> = {};
32	  for (const item of items) {
33	    countsByType[item.type] = (countsByType[item.type] ?? 0) + 1;
34	  }
35	
36	  let total = 0;
37	  for (const type of Object.keys(countsByType)) {
38	    if (BASE_PREMIUMS[type] === undefined) {
39	      throw new Error(`Unknown item type: ${type}`);
40	    }
41	    const count = countsByType[type];
42	    if (count === 3 && COMPONENT_BLOCK_PREMIUM[type] !== undefined) {
43	      total += COMPONENT_BLOCK_PREMIUM[type];
44	    } else {
45	      total += count * BASE_PREMIUMS[type];
46	    }
47	  }
48	  return total;
49	}
50	
51	function calculateItemSurcharges(items: any[]): number {
52	  let surcharges = 0;
53	  for (const item of items) {
54	    const itemBase = BASE_PREMIUMS[item.type];
55	    if (item.cursed) {
56	      surcharges += itemBase * CURSE_SURCHARGE_RATE;
57	    }
58	    if (item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
59	      surcharges += itemBase * HIGH_ENCHANTMENT_SURCHARGE_RATE;
60	    }
61	  }
62	  return surcharges;
63	}
64	
65	function calculatePremium(items: any[], customer: any, isFollowUp: boolean): number {
66	  const basePremium = calculateBasePremium(items);
67	  const itemSurcharges = calculateItemSurcharges(items);
68	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_RATE;
69	  const loyaltyDiscount = customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? basePremium * LOYALTY_DISCOUNT_RATE : 0;
70	  const followUpDiscount = isFollowUp ? basePremium * FOLLOW_UP_DISCOUNT_RATE : 0;
71	  return Math.ceil(basePremium + itemSurcharges + firstInsuranceSurcharge - loyaltyDiscount - followUpDiscount + PROCESSING_FEE);
72	}
73	
74	function reimbursementRateFor(item: any): number {
75	  if (item && item.enchantment >= CLAIM_ENCHANTMENT_THRESHOLD) {
76	    return CLAIM_ENCHANTMENT_REIMBURSEMENT_RATE;
77	  }
78	  return 1;
79	}
80	
81	function calculateDamagePayout(damage: any, policyItems: any[]): number {
82	  const matchedItem = policyItems.find((item: any) => item.type === damage.itemType);
83	  return damage.amount * reimbursementRateFor(matchedItem) - DEDUCTIBLE;
84	}
85	
86	function processClaim(
87	  policy: { items: any[]; insuranceSum: number; remainingCap: number },
88	  incident: any,
89	): { payout: number; remainingCap: number } {
90	  const totalPayout = Math.floor(
91	    incident.damages.reduce(
92	      (sum: number, damage: any) => sum + calculateDamagePayout(damage, policy.items),
93	      0,
94	    )
95	  );
96	  const clampedPayout = Math.min(totalPayout, policy.remainingCap);
97	  policy.remainingCap -= clampedPayout;
98	  return { payout: clampedPayout, remainingCap: policy.remainingCap };
99	}
100	
101	export function processScenario(scenario: any): unknown {
102	  const { customer } = scenario;
103	  const results: any[] = [];
104	  const policies: { items: any[]; insuranceSum: number; remainingCap: number }[] = [];
105	  let quotesSeen = 0;
106	  for (const step of scenario.steps) {
107	    if (step.op === "claim") {
108	      results.push(processClaim(policies[step.policy], step.incident));
109	    } else {
110	      const isFollowUp = quotesSeen > 0;
111	      const premium = calculatePremium(step.items, customer, isFollowUp);
112	      results.push({ premium });
113	      const insuranceSum = step.items.reduce(
114	        (sum: number, item: any) => sum + BASE_PREMIUMS[item.type] * INSURANCE_VALUE_MULTIPLIER,
115	        0
116	      );
117	      policies.push({ items: step.items, insuranceSum, remainingCap: 2 * insuranceSum });
118	      quotesSeen++;
119	    }
120	  }
121	  return { results };
122	}
